import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { UserProfile } from '../../models/auth.model';

@Component({
  selector: 'app-navbar',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './navbar.component.html',
  styleUrls: ['./navbar.component.scss']
})
export class NavbarComponent implements OnInit {
  private authService = inject(AuthService);
  private router = inject(Router);

  currentUser: UserProfile | null = null;
  showUserMenu = false;

  ngOnInit(): void {
    this.currentUser = this.authService.getCurrentUserSync();
    this.authService.currentUser$.subscribe(user => {
      this.currentUser = user;
    });
  }

  toggleUserMenu(): void {
    this.showUserMenu = !this.showUserMenu;
  }

  closeUserMenu(): void {
    this.showUserMenu = false;
  }

  logout(): void {
    this.authService.logout();
    this.router.navigate(['/auth/login']);
  }

  getCurrentUserDisplay(): string {
    if (this.currentUser?.firstName || this.currentUser?.username) {
      return this.currentUser?.firstName || this.currentUser?.username || 'User';
    }
    return 'User';
  }
}
<nav class="navbar">
  <div class="navbar-container">
    <div class="navbar-brand">
      <h2 class="app-title">📋 Task Manager</h2>
    </div>

    <div class="navbar-menu">
      <div class="user-menu-container">
        <button class="user-button" (click)="toggleUserMenu()">
          <span class="user-icon">👤</span>
          <span class="user-name">{{ getCurrentUserDisplay() }}</span>
          <span class="dropdown-arrow">▼</span>
        </button>

        @if (showUserMenu) {
          <div class="user-dropdown">
            <div class="dropdown-header">
              <p class="user-email">{{ currentUser?.email }}</p>
            </div>
            <div class="dropdown-divider"></div>
            <button class="dropdown-item logout-btn" (click)="logout()">
              <span class="logout-icon">🚪</span>
              <span>Sign Out</span>
            </button>
          </div>
        }
      </div>
    </div>
  </div>
</nav>
